class TokenBucket:
    def __init__(self, rate):
        self.tokens = rate
        self.rate = rate
    def allow(self):
        if self.tokens >= 1:
            self.tokens -= 1
            return True
        return False
b = TokenBucket(2)
print([b.allow() for _ in range(3)])
